declare const require: any;
declare const process: any;
const fs = require('node:fs');

export class CsvParser {
  private delimiter: string;

  constructor(options?: { delimiter?: string }) {
    this.delimiter = options?.delimiter ?? ',';
  }

  parse(text: string): Record<string, string>[] {
    const lines = text.split('\n');
    if (lines.length === 0) return [];

    const headers = lines[0].split(this.delimiter);
    const result: Record<string, string>[] = [];

    for (let i = 1; i < lines.length; i++) {
      const values = this.parseLine(lines[i]);
      const record: Record<string, string> = {};
      for (let j = 0; j < headers.length; j++) {
        record[headers[j]] = values[j];
      }
      result.push(record);
    }

    return result;
  }

  private parseLine(line: string): string[] {
    const values: string[] = [];
    let value = '';
    let inQuotes = false;

    for (let i = 0; i < line.length; i++) {
      const char = line[i];

      if (char === '"') {
        if (inQuotes && i + 1 < line.length && line[i + 1] === '"') {
          value += '"';
          i++;
        } else {
          inQuotes = !inQuotes;
        }
      } else if (char === this.delimiter && !inQuotes) {
        values.push(value);
        value = '';
      } else {
        value += char;
      }
    }

    values.push(value);
    return values;
  }

  stringify(rows: Record<string, string>[]): string {
    if (rows.length === 0) return '';

    const headers = Object.keys(rows[0]);
    const lines: string[] = [headers.join(this.delimiter)];

    for (const row of rows) {
      const values = headers.map(header => this.quoteField(row[header]));
      lines.push(values.join(this.delimiter));
    }

    return lines.join('\n');
  }

  private quoteField(value: string): string {
    if (value.includes(this.delimiter) || value.includes('"')) {
      return `"${value.replace(/"/g, '""')}"`;
    }
    return value;
  }
}

export class CsvFilter {
  private rows: Record<string, string>[];

  constructor(rows: Record<string, string>[]) {
    this.rows = rows;
  }

  where(predicate: (row: Record<string, string>) => boolean): CsvFilter {
    const filteredRows = this.rows.filter(predicate);
    return new CsvFilter(filteredRows);
  }

  select(columns: string[]): Record<string, string>[] {
    return this.rows.map(row => {
      const selectedRow: Record<string, string> = {};
      for (const column of columns) {
        if (row.hasOwnProperty(column)) {
          selectedRow[column] = row[column];
        }
      }
      return selectedRow;
    });
  }

  sortBy(column: string): CsvFilter {
    const sortedRows = [...this.rows].sort((a, b) => a[column].localeCompare(b[column]));
    return new CsvFilter(sortedRows);
  }

  count(): number {
    return this.rows.length;
  }
}

declare const require: any;
declare const process: any;
const fs = require('node:fs');
import { CsvParser, CsvFilter } from './csv';

function help() {
  console.log(`Usage:
  node dist/cli.js parse --input <file>
  node dist/cli.js stats --input <file>
  node dist/cli.js --help`);
}

if (process.argv.length < 3) {
  help();
  process.exit(1);
}

const command = process.argv[2];

if (command === '--help') {
  help();
  process.exit(0);
} else if (command === 'parse' || command === 'stats') {
  const inputIndex = process.argv.indexOf('--input');
  if (inputIndex === -1 || inputIndex + 1 >= process.argv.length) {
    console.error('Missing --input argument');
    process.exit(1);
  }

  const inputFile = process.argv[inputIndex + 1];
  if (!fs.existsSync(inputFile)) {
    console.error(`File not found: ${inputFile}`);
    process.exit(1);
  }

  const fileContent = fs.readFileSync(inputFile, 'utf8');
  const parser = new CsvParser();
  const rows = parser.parse(fileContent);

  if (command === 'parse') {
    console.log(JSON.stringify(rows));
  } else if (command === 'stats') {
    const filter = new CsvFilter(rows);
    console.log(`Rows: ${filter.count()}`);
    console.log(`Columns: ${Object.keys(rows[0]).join(', ')}`);
  }
} else {
  console.error('Unknown command');
  process.exit(1);
}
